import React, { useState, useEffect } from 'react';
import { Cpu, Plus, Play, Download, Moon, Sun, BarChart3, Settings, Home, User, Keyboard, Zap } from 'lucide-react';
import ProcessInput from './components/ProcessInput';
import GanttChart from './components/GanttChart';
import PerformanceMetrics from './components/PerformanceMetrics';
import AlgorithmSelector from './components/AlgorithmSelector';
import TypingTutor from './components/TypingTutor';
import TypingGame from './components/TypingGame';
import { schedulingAlgorithms } from './utils/schedulingAlgorithms';
import './App.css';

function App() {
  const [processes, setProcesses] = useState([]);
  const [selectedAlgorithm, setSelectedAlgorithm] = useState('fcfs');
  const [timeQuantum, setTimeQuantum] = useState(2);
  const [ganttData, setGanttData] = useState([]);
  const [performanceData, setPerformanceData] = useState(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentView, setCurrentView] = useState('home');
  const [isAnimating, setIsAnimating] = useState(false);
  const [stepMode, setStepMode] = useState(false);
  const [currentStep, setCurrentStep] = useState(0);
  const [typingMode, setTypingMode] = useState('tutor'); // 'tutor' or 'game'

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const runSimulation = () => {
    if (processes.length === 0) return;

    const algorithm = schedulingAlgorithms[selectedAlgorithm];
    const result = algorithm(processes, timeQuantum);

    setGanttData(result.ganttChart);
    setPerformanceData(result.metrics);

    if (stepMode) {
      setIsAnimating(true);
      animateSteps(result.ganttChart);
    }
  };

  const animateSteps = (ganttChart) => {
    let step = 0;
    const interval = setInterval(() => {
      if (step >= ganttChart.length) {
        clearInterval(interval);
        setIsAnimating(false);
        return;
      }
      setCurrentStep(step);
      step++;
    }, 1000);
  };

  const exportResults = () => {
    const results = {
      algorithm: selectedAlgorithm,
      timeQuantum: selectedAlgorithm === 'roundRobin' ? timeQuantum : null,
      processes: processes,
      ganttChart: ganttData,
      performanceMetrics: performanceData
    };

    const dataStr = JSON.stringify(results, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `cpu-scheduling-results-${Date.now()}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const renderMobileView = () => (
    <div className="min-h-screen pb-20">
      <header className="bg-white dark:bg-gray-800 shadow-sm">
        <div className="px-4 py-3 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <Cpu className="w-6 h-6 text-blue-600" />
            <h1 className="text-lg font-bold text-gray-900 dark:text-white">CPU Scheduler</h1>
          </div>
          <button
            onClick={() => setIsDarkMode(!isDarkMode)}
            className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700"
          >
            {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
        </div>
      </header>

      <main className="p-4 space-y-4">
        {currentView === 'home' && (
          <>
            <AlgorithmSelector
              selectedAlgorithm={selectedAlgorithm}
              setSelectedAlgorithm={setSelectedAlgorithm}
              timeQuantum={timeQuantum}
              setTimeQuantum={setTimeQuantum}
            />

            <ProcessInput
              processes={processes}
              setProcesses={setProcesses}
            />

            <div className="flex space-x-2">
              <button
                onClick={runSimulation}
                disabled={processes.length === 0}
                className="flex-1 bg-blue-600 text-white px-4 py-3 rounded-lg font-medium disabled:bg-gray-400 flex items-center justify-center space-x-2"
              >
                <Play className="w-4 h-4" />
                <span>Run Simulation</span>
              </button>

              <button
                onClick={() => setStepMode(!stepMode)}
                className={`px-4 py-3 rounded-lg font-medium ${stepMode ? 'bg-green-600 text-white' : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300'}`}
              >
                Step
              </button>
            </div>

            {ganttData.length > 0 && (
              <GanttChart
                data={ganttData}
                isAnimating={isAnimating}
                currentStep={currentStep}
                stepMode={stepMode}
              />
            )}

            {performanceData && (
              <PerformanceMetrics data={performanceData} />
            )}

            {performanceData && (
              <button
                onClick={exportResults}
                className="w-full bg-green-600 text-white px-4 py-3 rounded-lg font-medium flex items-center justify-center space-x-2"
              >
                <Download className="w-4 h-4" />
                <span>Export Results</span>
              </button>
            )}
          </>
        )}

        {currentView === 'typing' && (
          <>
            <div className="flex space-x-2 mb-4">
              <button
                onClick={() => setTypingMode('tutor')}
                className={`flex-1 px-4 py-2 rounded-lg font-medium ${typingMode === 'tutor' ? 'bg-blue-600 text-white' : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300'}`}
              >
                <Keyboard className="w-4 h-4 inline mr-2" />
                Typing Tutor
              </button>
              <button
                onClick={() => setTypingMode('game')}
                className={`flex-1 px-4 py-2 rounded-lg font-medium ${typingMode === 'game' ? 'bg-blue-600 text-white' : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300'}`}
              >
                <Zap className="w-4 h-4 inline mr-2" />
                Typing Game
              </button>
            </div>

            {typingMode === 'tutor' ? <TypingTutor /> : <TypingGame />}
          </>
        )}

        {currentView === 'analytics' && (
          <div className="text-center py-20">
            <BarChart3 className="w-16 h-16 mx-auto text-gray-400 mb-4" />
            <h2 className="text-xl font-semibold text-gray-700 dark:text-gray-300">Analytics View</h2>
            <p className="text-gray-500 dark:text-gray-400 mt-2">Compare different algorithms</p>
          </div>
        )}

        {currentView === 'settings' && (
          <div className="text-center py-20">
            <Settings className="w-16 h-16 mx-auto text-gray-400 mb-4" />
            <h2 className="text-xl font-semibold text-gray-700 dark:text-gray-300">Settings</h2>
            <p className="text-gray-500 dark:text-gray-400 mt-2">Configure simulation settings</p>
          </div>
        )}

        {currentView === 'profile' && (
          <div className="text-center py-20">
            <User className="w-16 h-16 mx-auto text-gray-400 mb-4" />
            <h2 className="text-xl font-semibold text-gray-700 dark:text-gray-300">Profile</h2>
            <p className="text-gray-500 dark:text-gray-400 mt-2">User profile information</p>
          </div>
        )}
      </main>

      <nav className="mobile-bottom-nav">
        <button
          onClick={() => setCurrentView('home')}
          className={`p-2 ${currentView === 'home' ? 'text-blue-600' : 'text-gray-500'}`}
        >
          <Home className="w-6 h-6" />
        </button>
        <button
          onClick={() => setCurrentView('analytics')}
          className={`p-2 ${currentView === 'analytics' ? 'text-blue-600' : 'text-gray-500'}`}
        >
          <BarChart3 className="w-6 h-6" />
        </button>
        <button
          onClick={() => setCurrentView('settings')}
          className={`p-2 ${currentView === 'settings' ? 'text-blue-600' : 'text-gray-500'}`}
        >
          <Settings className="w-6 h-6" />
        </button>
        <button
          onClick={() => setCurrentView('profile')}
          className={`p-2 ${currentView === 'profile' ? 'text-blue-600' : 'text-gray-500'}`}
        >
          <User className="w-6 h-6" />
        </button>
      </nav>
    </div>
  );

  const renderDesktopView = () => (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
      <header className="desktop-nav bg-white dark:bg-gray-800 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center space-x-8">
              <div className="flex items-center space-x-2">
                <Cpu className="w-8 h-8 text-blue-600" />
                <h1 className="text-2xl font-bold text-gray-900 dark:text-white">CPU Scheduling Simulator</h1>
              </div>
              <nav className="hidden md:flex space-x-6">
                <button className="text-gray-700 dark:text-gray-300 hover:text-blue-600 font-medium">Home</button>
                <button className="text-gray-700 dark:text-gray-300 hover:text-blue-600 font-medium">Analytics</button>
                <button className="text-gray-700 dark:text-gray-300 hover:text-blue-600 font-medium">Documentation</button>
              </nav>
            </div>
            <div className="flex items-center space-x-4">
              <button
                onClick={() => setIsDarkMode(!isDarkMode)}
                className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700"
              >
                {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
              </button>
              <button className="bg-blue-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-blue-700">
                Sign In
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-6">
            <AlgorithmSelector
              selectedAlgorithm={selectedAlgorithm}
              setSelectedAlgorithm={setSelectedAlgorithm}
              timeQuantum={timeQuantum}
              setTimeQuantum={setTimeQuantum}
            />

            <ProcessInput
              processes={processes}
              setProcesses={setProcesses}
            />

            <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">Simulation Controls</h3>
              <div className="space-y-3">
                <button
                  onClick={runSimulation}
                  disabled={processes.length === 0}
                  className="w-full bg-blue-600 text-white px-4 py-3 rounded-lg font-medium disabled:bg-gray-400 flex items-center justify-center space-x-2"
                >
                  <Play className="w-4 h-4" />
                  <span>Run Simulation</span>
                </button>

                <div className="flex space-x-2">
                  <button
                    onClick={() => setStepMode(!stepMode)}
                    className={`flex-1 px-4 py-2 rounded-lg font-medium ${stepMode ? 'bg-green-600 text-white' : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300'}`}
                  >
                    {stepMode ? 'Step Mode ON' : 'Step Mode OFF'}
                  </button>

                  {performanceData && (
                    <button
                      onClick={exportResults}
                      className="flex-1 bg-green-600 text-white px-4 py-2 rounded-lg font-medium flex items-center justify-center space-x-1"
                    >
                      <Download className="w-4 h-4" />
                      <span>Export</span>
                    </button>
                  )}
                </div>
              </div>
            </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
            {ganttData.length > 0 && (
              <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
                <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">Gantt Chart Visualization</h3>
                <GanttChart
                  data={ganttData}
                  isAnimating={isAnimating}
                  currentStep={currentStep}
                  stepMode={stepMode}
                />
              </div>
            )}

            {performanceData && (
              <PerformanceMetrics data={performanceData} />
            )}

            {ganttData.length === 0 && (
              <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-12 text-center">
                <Cpu className="w-16 h-16 mx-auto text-gray-400 mb-4" />
                <h3 className="text-xl font-semibold text-gray-700 dark:text-gray-300 mb-2">Ready to Simulate</h3>
                <p className="text-gray-500 dark:text-gray-400">Add processes and select an algorithm to begin the simulation</p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );

  return (
    <div className="App">
      {renderMobileView()}
      {renderDesktopView()}
    </div>
  );
}

export default App;
